sp_css.css:
/*
Tasker State styling for badge, button and pill shapes
Widgets:
  Tasker Portal Board with Filter
  Tasker Data Table (page detail and modal)
  Tasker States Progress Bar (progress bar in Tasker Dynamic Task Tree and Subtasks when "open task in new tab")
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  Put into a style sheet
*/

.Draft {
    background-color: $state-draft-bg;
		color: $state-draft-text;
}

.Waiting {
    background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

.Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text; 
}

.Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
} 

.Accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}

.Rejected {
 		background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

.Work.Scheduled {
  	background-color: $state-workscheduled-bg;
		color: $state-workscheduled-text;
}

.Work.in.Progress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

.In.Review {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

.Rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

.Completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}
/* 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color */
.Closed.Incomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

.Cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

/*
Widget: Tasker Graph - Task Tree
*/
//State = Draft
span.label.label-Draft,
span.label.label-pill.label-Draft {
  background-color: $state-draft-bg;
  color: $state-draft-text;
}

//State = Waiting
span.label.label-Waiting,
span.label.label-pill.label-Waiting {
  	background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

//State = Unassigned
span.label.label-Unassigned,
span.label.label-pill.label-Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text;  
}

//State = Assigned
span.label.label-Assigned,
span.label.label-pill.label-Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
}


//State = Accepted
span.label.label-Accepted,
span.label.label-pill.label-Accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}


//State = Rejected
span.label.label-Rejected,
span.label.label-pill.label-Rejected {
  	background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

//State = Work in Progress
span.label.label-Work.in.Progress,
span.label.label-pill.label-Work.in.Progress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

//State = Work in Progress
span.label.label-Work.Scheduled,
span.label.label-pill.label-Work.Scheduled {
	background-color: #2E3C54!important;
}


//State = In Review
span.label.label-InReview,
span.label.label-pill.label-In.Review {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

//State = Rework
span.label.label-Rework,
span.label.label-pill.label-Rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

//State = Close Complete
span.label.label-Completed,
span.label.label-pill.label-Completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}

//State = Close Incomplete
span.label.label-Closed.Incomplete,
span.label.label-pill.label-Closed.Incomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

//State = Close Skipped
span.label.label-Cancelled ,
span.label.label-pill.label-Cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

/*
Widget: Tasker States Progress Bar
*/
